import{_ as e,o as a,c as r,a0 as l}from"./chunks/framework.jwovEGr5.js";const g=JSON.parse('{"title":"📦 商店建立與設定指南","description":"","frontmatter":{},"headers":[],"relativePath":"Shop-Creation.md","filePath":"Shop-Creation.md"}'),t={name:"Shop-Creation.md"};function i(d,o,n,c,s,h){return a(),r("div",null,[...o[0]||(o[0]=[l('<h1 id="📦-商店建立與設定指南" tabindex="-1">📦 商店建立與設定指南 <a class="header-anchor" href="#📦-商店建立與設定指南" aria-label="Permalink to &quot;📦 商店建立與設定指南&quot;">​</a></h1><p>本章節介紹玩家如何建立箱子商店，以及系統如何透過步驟定價引導您完成設定。</p><hr><h2 id="_1-⚙️-建立商店的前置限制" tabindex="-1">1. ⚙️ 建立商店的前置限制 <a class="header-anchor" href="#_1-⚙️-建立商店的前置限制" aria-label="Permalink to &quot;1. ⚙️ 建立商店的前置限制&quot;">​</a></h2><p>在開始擺攤之前，請注意以下伺服器規則：</p><ul><li><strong>商店數量上限</strong>：每位玩家預設最多可建立 <strong>15 個商店</strong>。 <ul><li><em>升級方式：在遊戲內輸入 <code>/shop upgrade</code> 支付 $5,000 遊戲金幣，可永久解鎖額外 1 個商店額度。</em></li></ul></li><li><strong>防誤觸安全設計</strong>：為了防止玩家整理箱子時意外將其設定為商店，系統不允許直接對箱子進行定價。玩家必須先主動啟用「商店建立模式」才能進行綁定。</li></ul><hr><h2 id="_2-🟢-啟動商店建立模式" tabindex="-1">2. 🟢 啟動商店建立模式 <a class="header-anchor" href="#_2-🟢-啟動商店建立模式" aria-label="Permalink to &quot;2. 🟢 啟動商店建立模式&quot;">​</a></h2><ol><li>在遊戲內輸入 <code>/shop</code> 開啟商店圖形選單。</li><li>在選單底部的中間，點選綠色寶石圖示的 <strong><code>[ 新增商店 ]</code></strong> 按鈕。 <ul><li>該按鈕會顯示您目前的已建商店數與上限（例如：<code>目前數量: 2 / 15</code>）。</li></ul></li><li>點擊後，選單會自動關閉，您的聊天欄會收到以下提示： <code>§b[Craft-Core] §a★ 商店建立模式 ★</code><code>§f- 請在 30 秒內，手持欲上架的物品，對著您的箱子按【左鍵】。</code></li><li>您有 <strong>30 秒</strong> 的時限來選擇箱子。如果想提前結束，請在聊天欄輸入 <code>cancel</code> 關閉此模式。</li></ol><hr><h2 id="_3-📦-綁定箱子與上架商品" tabindex="-1">3. 📦 綁定箱子與上架商品 <a class="header-anchor" href="#_3-📦-綁定箱子與上架商品" aria-label="Permalink to &quot;3. 📦 綁定箱子與上架商品&quot;">​</a></h2><ol><li>手持您想要交易的物品（例如手拿一個 <code>鑽石</code>）。</li><li>對著您的箱子按**【左鍵】**。</li><li>系統會鎖定該箱子的座標，並確認您手持的物品為交易商品，隨後立即在聊天欄中為您開啟<strong>分步定價引導</strong>。</li></ol><hr><h2 id="_4-✍️-分步定價引導" tabindex="-1">4. ✍️ 分步定價引導 <a class="header-anchor" href="#_4-✍️-分步定價引導" aria-label="Permalink to &quot;4. ✍️ 分步定價引導&quot;">​</a></h2><p>定價引導完全在您的個人聊天欄中進行，您輸入的內容為私密訊息，其他玩家無法看見：</p><h3 id="🟢-步驟-1-2-設定出售價格" tabindex="-1">🟢 步驟 1/2：設定出售價格 <a class="header-anchor" href="#🟢-步驟-1-2-設定出售價格" aria-label="Permalink to &quot;🟢 步驟 1/2：設定出售價格&quot;">​</a></h3><ul><li><strong>系統提示</strong>： <code>§b[Craft-Core] §e【步驟 1/2】設定出售價格</code><code>§f- 請在聊天欄輸入「出售價格」（玩家買你商品的單價，如: 100）。</code><code>§f- 若不提供出售，請輸入「0」或「none」。</code><code>§f- 輸入「取消」可放棄建立。</code></li><li><strong>操作</strong>：直接在聊天欄發送您預期賣給別人的單價。若您只想收購、不想賣出該物品，請輸入 <code>0</code>。</li></ul><h3 id="🔵-步驟-2-2-設定收購價格" tabindex="-1">🔵 步驟 2/2：設定收購價格 <a class="header-anchor" href="#🔵-步驟-2-2-設定收購價格" aria-label="Permalink to &quot;🔵 步驟 2/2：設定收購價格&quot;">​</a></h3><ul><li><strong>系統提示</strong>： <code>§b[Craft-Core] §e【步驟 2/2】設定收購價格</code><code>§f- 請在聊天欄輸入「收購價格」（你向玩家收購商品的單價，如: 50）。</code><code>§f- 若不提供收購，請輸入「0」或「none」。</code><code>§f- 輸入「取消」可放棄建立。</code></li><li><strong>操作</strong>：直接在聊天欄發送您收購該物品的單價。若您只想賣出、不想收購，請輸入 <code>0</code>。</li></ul><hr><h2 id="_5-🎉-建立成功與自動生成元素" tabindex="-1">5. 🎉 建立成功與自動生成元素 <a class="header-anchor" href="#_5-🎉-建立成功與自動生成元素" aria-label="Permalink to &quot;5. 🎉 建立成功與自動生成元素&quot;">​</a></h2><p>當兩步驟定價均完成後，系統會自動儲存設定，並在箱子位置生成以下元素：</p><h3 id="a-壁掛告示牌-帶發光特效" tabindex="-1">A. 壁掛告示牌（帶發光特效） <a class="header-anchor" href="#a-壁掛告示牌-帶發光特效" aria-label="Permalink to &quot;A. 壁掛告示牌（帶發光特效）&quot;">​</a></h3><p>系統會自動在箱子的正面放置一個發光的壁掛告示牌：</p><ul><li><strong>第一行</strong>：<code>§1[商店]</code> (深藍色粗體，代表這是一個玩家商店)</li><li><strong>第二行</strong>：商店主人的玩家名稱（例如：<code>Yanggu</code>）</li><li><strong>第三行</strong>：商品名稱（自動根據顧客的遊戲語系翻譯，如繁體中文顯示 <code>鑽石</code>，英文顯示 <code>Diamond</code>）</li><li><strong>第四行</strong>：價格標示（例如：<code>售100 | 收50</code>，若有其中一項關閉，會顯示如 <code>售: 100</code> 或 <code>收: 無</code>）</li></ul><h3 id="b-懸浮商品模型" tabindex="-1">B. 懸浮商品模型 <a class="header-anchor" href="#b-懸浮商品模型" aria-label="Permalink to &quot;B. 懸浮商品模型&quot;">​</a></h3><p>箱子正上方會自動出現一個對應商品的懸浮展示模型：</p><ul><li>使用遊戲展示技術，<strong>不佔用實體碰撞體積</strong>，無重力，不影響任何生存建造。</li><li>展示物自動縮放為原大小的 <strong><code>0.5</code> 倍</strong>，精緻美觀。</li><li>具備自動清理機制，若箱子被破壞或商店註銷，懸浮物會瞬間被清理乾淨，不殘留伺服器垃圾。</li></ul>',28)])])}const _=e(t,[["render",i]]);export{g as __pageData,_ as default};
